function sortedSquares(nums) {
  const n = nums.length;
  const result = new Array(n);

  let left = 0;
  let right = n - 1;
  let write = n - 1;

  while (left <= right) {
    if (Math.abs(nums[left]) > Math.abs(nums[right])) {
      result[write] = nums[left] * nums[left];
      left++;
    } else {
      result[write] = nums[right] * nums[right];
      right--;
    }
    write--;
  }

  return result;
}
```
